// Check which applications need follow-ups today
const githubToken = process.env.GITHUB_TOKEN || '';
const today = new Date().toISOString().split('T')[0];

if (!githubToken) {
  return [{ json: { followups_needed: [], error: 'No GitHub token' } }];
}

const owner = 'odeliyach';
const repo = 'job-search-data';
const headers = {
  'Authorization': 'token ' + githubToken,
  'Accept': 'application/vnd.github.v3+json'
};

try {
  // Get the tracking files from the vault Active folder
  let trackingFiles = [];
  try {
    const contentsResp = await $helpers.httpRequest({
      method: 'GET',
      url: 'https://api.github.com/repos/' + owner + '/' + repo + '/contents/Obsidian_Vault/Active',
      headers: headers
    });
    // Look through each year/month/company folder for tracking.md files
    if (Array.isArray(contentsResp)) {
      for (const yearDir of contentsResp) {
        if (yearDir.type === 'dir') {
          try {
            const monthDirs = await $helpers.httpRequest({
              method: 'GET',
              url: 'https://api.github.com/repos/' + owner + '/' + repo + '/contents/' + yearDir.path,
              headers: headers
            });
            for (const monthDir of monthDirs) {
              if (monthDir.type === 'dir') {
                try {
                  const appDirs = await $helpers.httpRequest({
                    method: 'GET',
                    url: 'https://api.github.com/repos/' + owner + '/' + repo + '/contents/' + monthDir.path,
                    headers: headers
                  });
                  for (const appDir of appDirs) {
                    if (appDir.type === 'dir') {
                      trackingFiles.push(appDir.path + '/tracking.md');
                    }
                  }
                } catch (e) { /* skip */ }
              }
            }
          } catch (e) { /* skip */ }
        }
      }
    }
  } catch (e) {
    // Vault may not exist yet
    trackingFiles = [];
  }

  const followupsNeeded = [];

  // Check each tracking file for due dates
  for (const filePath of trackingFiles) {
    try {
      const fileResp = await $helpers.httpRequest({
        method: 'GET',
        url: 'https://api.github.com/repos/' + owner + '/' + repo + '/contents/' + filePath,
        headers: headers
      });
      const content = Buffer.from(fileResp.content, 'base64').toString('utf-8');

      // Parse follow-up dates from tracking.md
      const day3Match = content.match(/Day 3 check-in: (\d{4}-\d{2}-\d{2})/);
      const day7Match = content.match(/Day 7 follow-up: (\d{4}-\d{2}-\d{2})/);
      const day30Match = content.match(/Day 30 check-in: (\d{4}-\d{2}-\d{2})/);
      const day90Match = content.match(/90-day check-in: (\d{4}-\d{2}-\d{2})/);
      const companyMatch = content.match(/Company: ([^\n]+)/);
      const titleMatch = content.match(/Title: ([^\n]+)/);

      const company = companyMatch ? companyMatch[1].trim() : filePath;
      const title = titleMatch ? titleMatch[1].trim() : 'Position';

      const checks = [
        { date: day3Match ? day3Match[1] : null, type: 'day_3', label: 'Day 3 Check-In' },
        { date: day7Match ? day7Match[1] : null, type: 'day_7', label: 'Day 7 Follow-Up' },
        { date: day30Match ? day30Match[1] : null, type: 'day_30', label: 'Day 30 Check-In' },
        { date: day90Match ? day90Match[1] : null, type: 'day_90', label: '90-Day Check-In' }
      ];

      for (const check of checks) {
        if (check.date === today) {
          followupsNeeded.push({
            company: company,
            title: title,
            followup_type: check.type,
            followup_label: check.label,
            due_date: today,
            file_path: filePath
          });
        }
      }
    } catch (e) { /* skip */ }
  }

  return [{ json: { followups_needed: followupsNeeded, checked_date: today, files_checked: trackingFiles.length } }];

} catch (e) {
  return [{ json: { followups_needed: [], error: e.message } }];
}

// Generate follow-up messages for each application needing follow-up
const data = $input.item.json;
const followups = data.followups_needed || [];

if (followups.length === 0) {
  return [{ json: { message: 'No follow-ups needed today', date: data.checked_date } }];
}

async function callOllama(prompt) {
  try {
    const resp = await $helpers.httpRequest({
      method: 'POST',
      url: 'http://ollama:11434/api/generate',
      headers: { 'Content-Type': 'application/json' },
      body: { model: 'llama3.2', prompt: prompt, stream: false }
    });
    return (resp && resp.response) ? resp.response : '[No response]';
  } catch (e) {
    return '[Ollama Error: ' + e.message + ']';
  }
}

const results = [];

for (const followup of followups) {
  let prompt = '';

  if (followup.followup_type === 'day_3') {
    prompt =
      'Write a brief, professional follow-up email for ' + followup.company + ' ' + followup.title + ' position.\n' +
      'This is a Day 3 check-in - it has been 3 days since applying.\n' +
      'Keep it under 3 sentences. Show continued interest. Reference something specific about the company.\n' +
      'Be friendly and professional. Not pushy.\n' +
      'Subject line: Following up on ' + followup.title + ' Application';
  } else if (followup.followup_type === 'day_7') {
    prompt =
      'Write a follow-up email for ' + followup.company + ' ' + followup.title + ' position.\n' +
      'It has been 7 days since applying - no response yet.\n' +
      'Keep it under 4 sentences. Reiterate interest. Mention a specific skill or achievement relevant to them.\n' +
      'Ask if they need any additional information. Show initiative without being desperate.\n' +
      'Subject line: Re: ' + followup.title + ' Application - Following Up';
  } else if (followup.followup_type === 'post_phone') {
    prompt =
      'Write a thank you and follow-up email after a phone screen for ' + followup.company + ' ' + followup.title + '.\n' +
      'Send within 24 hours of the call.\n' +
      'Thank them for their time. Reference ONE specific topic from the conversation.\n' +
      'Reaffirm your interest and ask about next steps timeline.\n' +
      'Subject line: Thank You - ' + followup.title + ' Phone Interview';
  } else if (followup.followup_type === 'post_technical') {
    prompt =
      'Write a thank you email after a technical interview for ' + followup.company + ' ' + followup.title + '.\n' +
      'Send within 24 hours.\n' +
      'Thank the interviewer(s). Mention one interesting technical problem you enjoyed solving.\n' +
      'Show enthusiasm for the engineering culture. Ask about timeline for next steps.\n' +
      'Subject line: Thank You - Technical Interview for ' + followup.title;
  } else if (followup.followup_type === 'day_90') {
    prompt =
      'Write a 90-day reconnection email to ' + followup.company + ' for ' + followup.title + '.\n' +
      'You applied 90 days ago. Checking in about future opportunities.\n' +
      'Mention that you\'re still very interested. Reference your growth in the past 3 months.\n' +
      'Ask if any suitable roles have opened up. Keep it short and professional.\n' +
      'Subject line: Reconnecting - ' + followup.title + ' Interest';
  } else {
    prompt =
      'Write a brief follow-up email to ' + followup.company + ' for ' + followup.title + ' position.\n' +
      'This is a ' + followup.followup_label + ' check-in.\n' +
      'Keep it professional, under 3 sentences.';
  }

  const emailDraft = await callOllama(prompt);

  results.push({
    company: followup.company,
    title: followup.title,
    followup_type: followup.followup_type,
    followup_label: followup.followup_label,
    due_date: followup.due_date,
    email_draft: emailDraft
  });
}

return results.map(function(r) { return { json: r }; });

// Send daily digest of all follow-ups needed
const items = $input.all();

if (items.length === 0 || (items.length === 1 && items[0].json.message)) {
  return [{ json: { status: 'no_followups', date: new Date().toISOString().split('T')[0] } }];
}

let emailBody = '<html><body style="font-family: Arial, sans-serif; max-width: 700px; margin: 0 auto; padding: 20px;">';
emailBody += '<h2 style="color: #007bff;">Daily Follow-Up Digest - ' + new Date().toISOString().split('T')[0] + '</h2>';
emailBody += '<p>You have <strong>' + items.length + '</strong> follow-up(s) scheduled for today:</p>';

for (const item of items) {
  const d = item.json;
  emailBody +=
    '<div style="border: 1px solid #dee2e6; border-radius: 5px; padding: 15px; margin-bottom: 15px;">' +
    '<h3 style="color: #495057; margin-top: 0;">' + d.company + ' - ' + d.title + '</h3>' +
    '<p><strong>Type:</strong> ' + d.followup_label + ' | <strong>Due:</strong> ' + d.due_date + '</p>' +
    '<h4>Suggested Email:</h4>' +
    '<pre style="background: #f8f9fa; padding: 15px; border-radius: 5px; white-space: pre-wrap;">' + (d.email_draft || 'No draft generated') + '</pre>' +
    '</div>';
}

emailBody += '<p style="color: #6c757d; font-size: 0.9em;">Auto-generated by Job Search N8N Automation</p>';
emailBody += '</body></html>';

return [{ json: { email_html: emailBody, followup_count: items.length, date: new Date().toISOString().split('T')[0] } }];

// Check for post-phone and post-technical follow-ups (24h after interview)
const githubToken = process.env.GITHUB_TOKEN || '';
const today = new Date().toISOString().split('T')[0];
const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString().split('T')[0];

// Look for email logs from yesterday with interview type
if (!githubToken) {
  return [{ json: { post_interview_followups: [], info: 'No token' } }];
}

const owner = 'odeliyach';
const repo = 'job-search-data';
const headers = {
  'Authorization': 'token ' + githubToken,
  'Accept': 'application/vnd.github.v3+json'
};

const followups = [];

try {
  // Check email log for yesterday's interview invites
  const logPath = 'Obsidian_Vault/Email_Log/' + yesterday + '-interview_invite.md';
  try {
    const fileResp = await $helpers.httpRequest({
      method: 'GET',
      url: 'https://api.github.com/repos/' + owner + '/' + repo + '/contents/' + logPath,
      headers: headers
    });
    const content = Buffer.from(fileResp.content, 'base64').toString('utf-8');
    const fromMatch = content.match(/From: ([^\n]+)/);
    const company = fromMatch ? fromMatch[1] : 'Unknown Company';
    followups.push({
      company: company,
      title: 'Position',
      followup_type: 'post_phone',
      followup_label: 'Post-Phone Screen (24h Thank You)',
      due_date: today
    });
  } catch (e) { /* No interview email yesterday */ }

  return [{ json: { post_interview_followups: followups, checked_date: today } }];
} catch (e) {
  return [{ json: { post_interview_followups: [], error: e.message } }];
}

const data = $input.item.json;
const followups = data.post_interview_followups || [];

if (followups.length === 0) {
  return [{ json: { message: 'No post-interview follow-ups today' } }];
}

async function callOllama(prompt) {
  try {
    const resp = await $helpers.httpRequest({
      method: 'POST',
      url: 'http://ollama:11434/api/generate',
      headers: { 'Content-Type': 'application/json' },
      body: { model: 'llama3.2', prompt: prompt, stream: false }
    });
    return resp && resp.response ? resp.response : '[No response]';
  } catch (e) {
    return '[Error: ' + e.message + ']';
  }
}

const results = [];
for (const f of followups) {
  const prompt =
    'Write a professional thank-you follow-up email 24 hours after a phone screen with ' + f.company + '.\n' +
    'Keep it to 3-4 sentences. Thank them, reference the conversation, ask about next steps timeline.\n' +
    'Be enthusiastic but not desperate. Professional tone.';
  const draft = await callOllama(prompt);
  results.push({ json: { ...f, email_draft: draft } });
}
return results;
